int MOD = 1000000007;
long long modpow(long long b, long long e, long long m) {
    long long r = 1;
    b %= m;
    while (e > 0) {
        if (e & 1) r = r * b % m;
        b = b * b % m;
        e >>= 1;
    }
    return r;
}
printf("%lld", modpow(2, 10, MOD));

